DROP TABLE IF EXISTS article_canvas_records;
CREATE TABLE article_canvas_records (record_id TEXT PRIMARY KEY, article_slug TEXT NOT NULL, article_title TEXT NOT NULL, module_kind TEXT NOT NULL, article_stage TEXT NOT NULL, canvas_dimension TEXT NOT NULL, description TEXT NOT NULL, content_value REAL NOT NULL, audience_value REAL NOT NULL, evidence_strength REAL NOT NULL, repository_support REAL NOT NULL, governance_need REAL NOT NULL, ethical_risk REAL NOT NULL, owner TEXT NOT NULL, status TEXT NOT NULL, review_date TEXT NOT NULL);
